import React, { useEffect, useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';

const WelcomePage = () => {
  const [stage, setStage] = useState('intro'); // intro -> main

  useEffect(() => {
    // Reveal timing: 3.5s for the trace/highlight, then transition to site
    const timer = setTimeout(() => setStage('main'), 4000);
    return () => clearTimeout(timer);
  }, []);

  const featuresRow1 = [
    { title: 'Course Curator', desc: 'AI picks the single best video for your concept.' },
    { title: 'Quiz Generator', desc: 'Adaptive questions with explanations.' },
    { title: 'Notes Generator', desc: 'Live summaries and key concepts.' },
    { title: 'Course Curator', desc: 'AI picks the single best video.' },
  ];

  const featuresRow2 = [
    { title: 'Revision Scheduler', desc: 'Smart reminders for better retention.' },
    { title: 'Update Acknowledger', desc: 'Stay updated within 48 hours.' },
    { title: 'Premium Features', desc: 'Unlock full learning power.' },
    { title: 'Revision Scheduler', desc: 'Smart reminders.' },
  ];

  return (
    <div className="min-h-screen bg-white text-[#0B3954] overflow-x-hidden font-serif">

      {/* 1. ARCHITECTURAL INTRO ANIMATION */}
      <AnimatePresence>
        {stage === 'intro' && (
          <motion.div
            key="intro-loader"
            className="fixed inset-0 flex items-center justify-center bg-white z-50"
            exit={{ opacity: 0, transition: { duration: 1, ease: "easeInOut" } }}
          >
            <div className="relative w-80 h-80 flex items-center justify-center">

              {/* THE IMAGE REVEAL (SVG MASK TECHNIQUE) */}
              <motion.div 
                className="relative"
                initial={{ opacity: 0 }}
                animate={{ opacity: 1 }}
                transition={{ duration: 0.5 }}
              >
                {/* SVG Mask to simulate tracing the brain edges */}
                <svg className="absolute inset-0 w-full h-full z-10 pointer-events-none" viewBox="0 0 100 100">
                  <motion.path
                    d="M50,85 C30,85 15,70 15,50 C15,30 30,15 50,15 C70,15 85,30 85,50 C85,60 80,75 70,85 L65,95 L55,85"
                    fill="none"
                    stroke="white" 
                    strokeWidth="100" // Acts as a "wipe" cover
                    strokeDasharray="400"
                    initial={{ strokeDashoffset: 400 }}
                    animate={{ strokeDashoffset: 0 }}
                    transition={{ duration: 2.5, ease: "easeInOut" }}
                  />
                </svg>

                <img 
                  src="/logo.jpeg" 
                  alt="Logo"
                  className="w-72 h-72 object-contain"
                />

                {/* THE PLAY BUTTON HIGHLIGHT (Professional Glow) */}
                <motion.div 
                  className="absolute z-20 w-14 h-14 rounded-full border-2 border-[#0B3954]/20 shadow-[0_0_40px_rgba(11,57,84,0.3)]"
                  style={{ top: '42%', left: '41%' }}
                  initial={{ scale: 0, opacity: 0 }}
                  animate={{ scale: [1, 1.2, 1], opacity: [0, 1, 0.6] }}
                  transition={{ delay: 2.2, duration: 1.5, repeat: Infinity }}
                />
              </motion.div>
            </div>
          </motion.div>
        )}
      </AnimatePresence>

      {/* 2. MAIN SITE CONTENT */}
      {stage === 'main' && (
        <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} transition={{ duration: 1.5 }}>

          {/* REFINED HEADER */}
          <header className="fixed top-0 left-0 right-0 h-24 flex items-center justify-between px-12 z-40 bg-white/70 backdrop-blur-2xl border-b border-gray-50">
            <div className="flex items-center gap-4"> 
              <img 
                src="/logo.jpeg" 
                alt="Logo" 
                className="h-12 w-auto object-contain mix-blend-multiply" 
              />
              <span className="text-xl font-bold tracking-tighter uppercase">CourseCraft</span>
            </div>

            <div className="flex items-center space-x-10">
              <button className="text-[10px] font-bold tracking-[0.3em] uppercase opacity-60 hover:opacity-100 transition-opacity">Log In</button>
              <button className="px-10 py-4 bg-[#0B3954] text-white rounded-full text-[10px] font-bold tracking-[0.3em] uppercase shadow-xl hover:scale-105 transition-all">
                Sign Up
              </button>
            </div>
          </header>

          {/* HERO SECTION */}
          <section className="h-screen flex flex-col items-center justify-center text-center px-6">
            <motion.div initial={{ y: 30, opacity: 0 }} animate={{ y: 0, opacity: 1 }} transition={{ delay: 0.4 }}>
              <h1 className="text-7xl md:text-[10rem] leading-[0.85] tracking-tighter text-black">
                Master any <br />
                <span className="italic font-light text-[#0B3954]">Skill.</span>
              </h1>
              <p className="mt-12 text-sm md:text-base tracking-[0.7em] uppercase text-gray-400 font-light">
                Curated by AI. <span className="text-black font-semibold">Mastered by you.</span>
              </p>
            </motion.div>
          </section>

          {/* FEATURES SCROLL SECTION */}
          <section className="py-40 bg-[#0B3954] text-white overflow-hidden">
            <div className="flex mb-12">
              <motion.div 
                className="flex space-x-10 px-4"
                animate={{ x: [0, -1200] }}
                transition={{ duration: 30, repeat: Infinity, ease: "linear" }}
              >
                {[...featuresRow1, ...featuresRow1].map((f, i) => (
                  <div key={i} className="min-w-[450px] h-72 p-12 bg-white/5 border border-white/10 rounded-[2.5rem] flex flex-col justify-end hover:bg-white/10 transition-colors">
                    <h3 className="text-2xl font-bold mb-3">{f.title}</h3>
                    <p className="text-white/50 text-lg leading-relaxed">{f.desc}</p>
                  </div>
                ))}
              </motion.div>
            </div>

            <div className="flex">
              <motion.div 
                className="flex space-x-10 px-4"
                animate={{ x: [-1200, 0] }}
                transition={{ duration: 30, repeat: Infinity, ease: "linear" }}
              >
                {[...featuresRow2, ...featuresRow2].map((f, i) => (
                  <div key={i} className="min-w-[450px] h-72 p-12 bg-white/5 border border-white/10 rounded-[2.5rem] flex flex-col justify-end hover:bg-white/10 transition-colors">
                    <h3 className="text-2xl font-bold mb-3">{f.title}</h3>
                    <p className="text-white/50 text-lg leading-relaxed">{f.desc}</p>
                  </div>
                ))}
              </motion.div>
            </div>
          </section>

          <footer className="py-20 flex flex-col items-center justify-center bg-white border-t border-gray-50">
             <img src="/logo.jpeg" alt="footer-logo" className="h-20 opacity-20 grayscale mb-6 mix-blend-multiply" />
             <p className="text-[9px] tracking-[0.6em] text-gray-400 uppercase">© 2026 CourseCraft Studio</p>
          </footer>
        </motion.div>
      )}
    </div>
  );
};

export default WelcomePage;
